#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005]; scanf("%s",s);
        int cnt0=0,cnt1=0;
        for(int i=0;i<N;i++){
            if(s[i]=='0') cnt0++; else cnt1++;
        }
        int moves = cnt0<cnt1?cnt0:cnt1;
        if(moves%2) printf("Zlatan\n"); else printf("Ramos\n");
    }
    return 0;
}

