const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let result = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  let cnt0 = 0;
  for (let i = 0; i < N; i++) if (s[i] === '0') cnt0++;
  const cnt1 = N - cnt0;
  const moves = cnt0 < cnt1 ? cnt0 : cnt1;
  result.push(moves % 2 ? 'Zlatan' : 'Ramos');
}
console.log(result.join('\n'));

